stereotypeDefinition.displayFunction:
const ApiGatewayRouteSettings = "1ad354a7-9ef2-440f-acb2-d9cb11be3352";
const ApiGatewayRoute = "83bfc247-76f5-476d-8741-0ecd7f9971ed";
const ApiGatewayMethod = "b8999d96-2f39-41bc-830a-9444114cb82e";

function getMethodAndRoute(element) {
    // Get custom settings
    const customSettings = element.getStereotype(ApiGatewayRouteSettings);
    const customRoute = customSettings?.getProperty(ApiGatewayRoute)?.getValue() || "";
    const customMethod = customSettings?.getProperty(ApiGatewayMethod)?.getValue() || "";

    // Get HTTP settings
    const endpoints = element.getAssociations("Route Association")
        .map(x => x.typeReference.getType())
        .filter(x => x);

    if (endpoints.length === 0) {
        return { method: "", route: "", result: "None" };
    }
    if (endpoints.length > 1) {
        return { method: "", route: "", result: "Aggregate" };
    }

    const httpSettings = endpoints[0].getStereotype("Http Settings");
    const httpMethod = httpSettings.getProperty("Verb").getValue();
    const httpRoute = httpSettings.getProperty("Route").getValue();

    // Use custom values if available, otherwise fall back to HTTP settings
    return {
        method: customMethod || httpMethod,
        route: customRoute || httpRoute
    };
}

function formatMethodAndRoute(element) {
    const { method, route, result } = getMethodAndRoute(element);

    if (result === "None") return "[Disconnected]";
    if (result === "Aggregate") return "[Aggregate]";

    return `${method} ("${route}")`;
}

return formatMethodAndRoute(element);
